SELECT image_path
FROM character_images
WHERE image_id = 1;

SELECT metric_name
FROM character_metrics
WHERE metric_source = 'system';

SELECT confidence_score
FROM document_characters
WHERE confidence_score > 0.8;

SELECT image_quality, COUNT(*) as image_count
FROM character_images
GROUP BY image_quality;

SELECT AVG(confidence_score) AS avg_confidence, COUNT(*) AS total_chars
FROM document_characters
WHERE doc_id = 1;

SELECT char_id, COUNT(variant_id) AS variant_count
FROM character_variants
GROUP BY char_id;

SELECT MAX(metric_value) AS max_skew_value
FROM character_metrics
WHERE metric_name = 'skew';

SELECT SUM(image_size) AS total_image_size
FROM character_images
WHERE upload_date = '2023-05-01';
